"""A shopping cart with line-item management and discount support.

This module provides:
    - ``CartItem``: an immutable value object describing a single line item.
    - ``Discount`` hierarchy: composable strategies for reducing a subtotal.
    - ``ShoppingCart``: an aggregate that owns its line items and computes totals.

All monetary values are represented with :class:`decimal.Decimal` to avoid the
rounding errors inherent in binary floating point arithmetic.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, replace
from decimal import Decimal, ROUND_HALF_UP
from typing import Iterable

__all__ = [
    "CartItem",
    "Discount",
    "PercentageDiscount",
    "FlatDiscount",
    "ShoppingCartError",
    "ItemNotFoundError",
    "DuplicateItemError",
    "InvalidQuantityError",
    "InvalidPriceError",
    "InvalidDiscountError",
    "ShoppingCart",
]

_CENT = Decimal("0.01")


# --------------------------------------------------------------------------- #
# Exceptions
# --------------------------------------------------------------------------- #
class ShoppingCartError(Exception):
    """Base class for every error raised by this module."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product that is not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that already exists in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item named {product_name!r} is already in the cart; "
            f"update its quantity instead."
        )
        self.product_name = product_name


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity!r}.")
        self.quantity = quantity


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative, got {unit_price!r}.")
        self.unit_price = unit_price


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is configured with an out-of-range value."""


# --------------------------------------------------------------------------- #
# Value objects
# --------------------------------------------------------------------------- #
@dataclass(frozen=True)
class CartItem:
    """A single line item in a shopping cart.

    Instances are immutable; mutating operations on the cart produce new
    ``CartItem`` objects rather than modifying existing ones.
    """

    product_name: str
    unit_price: Decimal
    quantity: int

    def __post_init__(self) -> None:
        if self.unit_price < Decimal("0"):
            raise InvalidPriceError(self.unit_price)
        if self.quantity <= 0:
            raise InvalidQuantityError(self.quantity)

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line item before any discount."""
        return self.unit_price * self.quantity


# --------------------------------------------------------------------------- #
# Discount strategies
# --------------------------------------------------------------------------- #
class Discount(ABC):
    """Strategy interface for reducing a subtotal to a discounted amount."""

    @abstractmethod
    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Return ``subtotal`` reduced by this discount, never below zero."""


@dataclass(frozen=True)
class PercentageDiscount(Discount):
    """A discount expressed as a percentage of the subtotal (0-100)."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if not Decimal("0") <= self.percentage <= Decimal("100"):
            raise InvalidDiscountError(
                f"Percentage must be between 0 and 100, got {self.percentage!r}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        reduction = subtotal * self.percentage / Decimal("100")
        return subtotal - reduction


@dataclass(frozen=True)
class FlatDiscount(Discount):
    """A discount that subtracts a fixed amount from the subtotal."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < Decimal("0"):
            raise InvalidDiscountError(
                f"Flat discount must not be negative, got {self.amount!r}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return max(Decimal("0"), subtotal - self.amount)


# --------------------------------------------------------------------------- #
# Aggregate
# --------------------------------------------------------------------------- #
class ShoppingCart:
    """A collection of line items that computes subtotals and discounted totals.

    Items are keyed by product name, so each product appears at most once. Use
    :meth:`update_quantity` to change an existing item rather than re-adding it.
    """

    def __init__(self) -> None:
        """Create an empty cart with no active discount."""
        self._items_by_name: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    # -- Item management ---------------------------------------------------- #
    def add_item(
        self, product_name: str, unit_price: Decimal, quantity: int
    ) -> CartItem:
        """Add a new item and return it.

        Raises:
            DuplicateItemError: If an item with ``product_name`` already exists.
            InvalidPriceError: If ``unit_price`` is negative.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        if product_name in self._items_by_name:
            raise DuplicateItemError(product_name)
        item = CartItem(product_name, unit_price, quantity)
        self._items_by_name[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove the item named ``product_name``.

        Raises:
            ItemNotFoundError: If no such item exists.
        """
        self._require_item(product_name)
        del self._items_by_name[product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing item and return the updated item.

        Raises:
            ItemNotFoundError: If no such item exists.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        updated_item = replace(existing_item, quantity=quantity)
        self._items_by_name[product_name] = updated_item
        return updated_item

    def clear(self) -> None:
        """Remove every item and any active discount."""
        self._items_by_name.clear()
        self._discount = None

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all line items as an immutable, insertion-ordered tuple."""
        return tuple(self._items_by_name.values())

    # -- Discounts ---------------------------------------------------------- #
    def apply_discount(self, discount: Discount) -> None:
        """Set the discount applied when computing the total.

        A cart holds at most one discount; calling this again replaces it.
        """
        self._discount = discount

    def remove_discount(self) -> None:
        """Clear any active discount."""
        self._discount = None

    # -- Totals ------------------------------------------------------------- #
    def subtotal(self) -> Decimal:
        """Return the sum of every line total before discounts, rounded to cents."""
        raw_subtotal = sum(
            (item.line_total for item in self._items_by_name.values()),
            start=Decimal("0"),
        )
        return self._round_to_cents(raw_subtotal)

    def total(self) -> Decimal:
        """Return the subtotal after the active discount, rounded to cents."""
        subtotal = self.subtotal()
        if self._discount is None:
            return subtotal
        return self._round_to_cents(self._discount.apply_to(subtotal))

    # -- Internal helpers --------------------------------------------------- #
    def _require_item(self, product_name: str) -> CartItem:
        """Return the named item or raise :class:`ItemNotFoundError`."""
        try:
            return self._items_by_name[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None

    @staticmethod
    def _round_to_cents(amount: Decimal) -> Decimal:
        """Round a monetary amount to two decimal places (half-up)."""
        return amount.quantize(_CENT, rounding=ROUND_HALF_UP)

    # -- Dunder conveniences ------------------------------------------------ #
    def __contains__(self, product_name: object) -> bool:
        return product_name in self._items_by_name

    def __len__(self) -> int:
        return len(self._items_by_name)

    def __iter__(self) -> Iterable[CartItem]:
        return iter(self._items_by_name.values())
```

## Design notes

**Data modeling** — `CartItem` is a `frozen=True` dataclass (immutable value object) with validation in `__post_init__` and a `line_total` computed property, so cost-per-line logic lives in one place.

**SOLID**
- **SRP**: each method does one thing — `add_item`/`remove_item`/`update_quantity`/`clear` mutate state, `subtotal`/`total` compute, `list_items` reads. Rounding and lookup are factored into private helpers.
- **Open/Closed + Strategy**: discounts are a `Discount` ABC with `PercentageDiscount` and `FlatDiscount` implementations. New discount types (BOGO, tiered, coupon stacking) drop in without touching `ShoppingCart`.
- **DRY**: `_require_item` centralizes the "fetch or raise" pattern used by both remove and update; `_round_to_cents` centralizes money rounding.

**Correctness** — `Decimal` throughout (never `float`) for money, with explicit `ROUND_HALF_UP` quantization to cents. `FlatDiscount` floors at zero so a total can't go negative.

**Edge cases / exceptions** — a typed exception hierarchy rooted at `ShoppingCartError`, each carrying the offending value as an attribute and a descriptive message — no bare `ValueError` or generic `Exception`.

**Style** — full type hints on every parameter and return, docstrings on the class and all public methods, descriptive names throughout, no mutable default arguments (dict/discount initialized in `__init__`), and no `print` — every method returns its result.

A couple of intentional choices worth flagging for review: items are keyed by `product_name` (enforcing uniqueness, hence `DuplicateItemError` rather than silent quantity-merge — I'd confirm that's the desired semantic), and the cart holds a single replaceable discount rather than a stack.

